const item = $input.first();
const headers = item.json.headers || {};
const receivedSecret = headers['x-fluxperf-webhook-secret'] || headers['X-Fluxperf-Webhook-Secret'];
const expectedSecret = $vars.MYFLUXPERF_RIB_WEBHOOK_SECRET;

if (!expectedSecret) {
  throw new Error('MYFLUXPERF_RIB_WEBHOOK_SECRET is not configured in n8n variables.');
}

if (receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized MyFluxperf RIB webhook request.');
}

const rawPayload = item.json.body?.payload ?? item.json.payload;
const payload = typeof rawPayload === 'string' ? JSON.parse(rawPayload) : rawPayload;
const binary = item.binary || {};
const rib = binary.rib;
const allowedMimeTypes = {
  'application/pdf': 'pdf',
  'image/jpeg': 'jpg',
  'image/png': 'png'
};

if (!payload?.documentId || !payload?.submittedAt || !payload?.client?.id || !payload?.client?.companyName || !payload?.requester?.email || payload?.document?.type !== 'rib_iban') {
  throw new Error('Invalid MyFluxperf RIB payload.');
}

if (!rib || !allowedMimeTypes[rib.mimeType]) {
  throw new Error('The webhook must contain one PDF, JPG or PNG file in the binary field rib.');
}

const submittedAt = new Date(payload.submittedAt);
if (Number.isNaN(submittedAt.getTime())) {
  throw new Error('Invalid RIB submission date.');
}

const dateParts = new Intl.DateTimeFormat('fr-FR', {
  timeZone: 'Europe/Paris',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
}).formatToParts(submittedAt);
const datePart = (type) => dateParts.find((part) => part.type === type)?.value || '';
const compactDate = `${datePart('day')}${datePart('month')}${datePart('year')}`;
const normalizedCompanyName = String(payload.client.companyName)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toUpperCase()
  .replace(/[^A-Z0-9]+/g, '_')
  .replace(/^_+|_+$/g, '') || 'CLIENT';

return [{
  json: {
    documentId: payload.documentId,
    submittedAt: payload.submittedAt,
    clientId: payload.client.id,
    companyName: payload.client.companyName,
    companyFolderName: String(payload.client.companyName).trim() || 'Client Fluxperf',
    requesterEmail: payload.requester.email,
    documentType: 'rib_iban',
    ribFileName: `${normalizedCompanyName}_RIB-IBAN-${compactDate}.${allowedMimeTypes[rib.mimeType]}`
  },
  binary: { rib }
}];

const normalized = $('Validate + Normalize RIB').first();
const existingDocument = $input.all()
  .map((item) => item.json)
  .filter((document) =>
    String(document.client_id || '') === normalized.json.clientId
    && String(document.document_type || '') === 'rib_iban'
    && String(document.drive_folder_id || '').trim()
  )
  .sort((left, right) => String(right.submitted_at || '').localeCompare(String(left.submitted_at || '')))[0];

return [{
  json: {
    ...normalized.json,
    driveFolderId: existingDocument?.drive_folder_id || ''
  },
  binary: normalized.binary
}];

const resolved = $('Resolve RIB Folder').first();
const createdFolder = $input.first().json;

if (!createdFolder.id) {
  throw new Error('Google Drive did not return the created client folder ID.');
}

return [{
  json: {
    ...resolved.json,
    driveFolderId: createdFolder.id
  },
  binary: resolved.binary
}];

const normalized = $('Validate + Normalize RIB').first().json;
const uploaded = $input.first().json;
const driveFolderId = Array.isArray(uploaded.parents) ? uploaded.parents[0] : '';

if (!uploaded.id || !driveFolderId) {
  throw new Error('Google Drive did not return the uploaded file and parent folder IDs.');
}

return [{
  json: {
    document_id: normalized.documentId,
    client_id: normalized.clientId,
    document_type: normalized.documentType,
    company_name: normalized.companyName,
    drive_folder_id: driveFolderId,
    drive_file_id: uploaded.id,
    file_name: normalized.ribFileName,
    submitted_at: normalized.submittedAt,
    submitted_by_email: normalized.requesterEmail,
    status: 'complete'
  }
}];

const normalized = $('Validate + Normalize RIB').first().json;

return [{
  json: {
    action_id: `ACT-${normalized.documentId}`,
    client_id: normalized.clientId,
    date_action: normalized.submittedAt,
    type_action: 'rib_submission',
    libelle_action: 'RIB/IBAN transmis',
    reference: normalized.documentId,
    email_demandeur: normalized.requesterEmail,
    source: 'myfluxperf',
    statut: 'complete',
    details: 'Document RIB/IBAN enregistré dans le dossier administratif sécurisé.'
  }
}];

const normalized = $('Validate + Normalize RIB').first().json;
const record = $('Build RIB Document Record').first().json;
const escapeHtml = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;');
const fileUrl = `https://drive.google.com/file/d/${record.drive_file_id}/view`;

return [{
  json: {
    brevoBody: {
      sender: {
        name: $vars.BREVO_FROM_NAME || 'Fluxperf',
        email: $vars.BREVO_FROM_EMAIL || 'notifications@fluxperf.fr'
      },
      to: [{
        email: $vars.MYFLUXPERF_SUPPORT_EMAIL || 'support@fluxperf.fr',
        name: 'Support Fluxperf'
      }],
      subject: `Nouveau RIB reçu — ${normalized.companyName}`,
      htmlContent: `<p>Un nouveau RIB a été déposé depuis MyFluxperf.</p><ul><li><strong>Client :</strong> ${escapeHtml(normalized.companyName)}</li><li><strong>Déposant :</strong> ${escapeHtml(normalized.requesterEmail)}</li><li><strong>Date :</strong> ${escapeHtml(normalized.submittedAt)}</li></ul><p><a href="${fileUrl}">Ouvrir le document dans Google Drive</a></p>`,
      textContent: `Un nouveau RIB a été déposé. Client : ${normalized.companyName}. Déposant : ${normalized.requesterEmail}. Date : ${normalized.submittedAt}. Document : ${fileUrl}`
    }
  }
}];
